+    #[test]
+    fn cleanup_plan_serde_preserves_table_order() {
+        let p = CleanupPlan {
+            tables: vec![
+                CleanupTableSummary {
+                    table: "z_last".to_string(),
+                    eligible_rows: 1,
+                    deleted_rows: 0,
+                    retention_days: 7,
