+    #[test]
+    fn retention_cutoff_ms_negative_now() {
+        // Hypothetical: negative now_ms (before epoch)
+        let now = -1_000_000i64;
+        let cutoff = retention_cutoff_ms(now, 1);
+        assert_eq!(cutoff, now - 86_400_000);
+        assert!(cutoff < now);
+    }
